var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"저기 봐. 하트베리 가은이다.","JPN":"あれ見て。ハートベリーのユキだ。","ENG":"Look! It's Gaeun of HRT Berry!","TWN":"你看，是愛心莓果的嘉恩欸！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘 정기 휴방일이지? 쉬러 나온 건가?","JPN":"今日は配信おやすみの日だよね？　オフのお出かけ？","ENG":"Today is her regular day off, isn't it? Is she out to have some fun on her own?","TWN":"今天沒有直播對吧？她是出來放鬆的嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"같이 사진 찍어달라고 하면 싫어할까?","JPN":"写真をお願いしたら断られちゃうかな？","ENG":"Would she hate it if I ask her to take a photo with us?","TWN":"去找她合照的話她會不開心嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"뭔가 방송에서 보던 분위기랑 다르지 않아?","JPN":"なんか放送の時の雰囲気と違うと思わない？","ENG":"She looks different from what she does on the show, doesn't she?","TWN":"本人和直播時的感覺好像不太一樣欸？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그러네. 웃고 있어.","JPN":"そうだね。笑ってる。","ENG":"Yes. She's smiling.","TWN":"對啊！她笑得好開心。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그런데 같이 다니고 있는 저 로봇은 뭐지?","JPN":"ところで一緒に歩いているあのロボットは何だろう？","ENG":"By the way, what's that robot beside her?","TWN":"不過走在她旁邊的那個機器人是什麼東東？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"머신 갑으로 나와서 미안하군, 가은 양.","JPN":"マシーン-甲-の姿で出てきてすまないな、ユキさん。","ENG":"I'm sorry I can only be out as Machine G.A.P., Gaeun.","TWN":"嘉恩，真是不好意思，我用這副機器人的裝扮出來和你見面。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이렇게 사람 많은 번화가는 다니기가 어려워서 말이야.","JPN":"人が多い繁華街に出るのは少し厳しくてな。","ENG":"It's difficult for me to be in such a crowded place.","TWN":"因為我不方便在這麼多人的街上露面。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"전 괜찮아요, 선생님.","JPN":"私は平気です、先生。","ENG":"I understand, Teacher.","TWN":"沒關係的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"선생님이 절 위해 시간을 써 주시고 있다는 사실엔 변함이 없는 걸요.","JPN":"先生が私のために時間を割いてくれている事実は変わりません。","ENG":"You're spending time with me, and that's what matters.","TWN":"謝謝你願意花時間在我的身上。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"게다가…….","JPN":"それに……","ENG":"Besides—","TWN":"而且……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"어?","JPN":"えっ？","ENG":"Err?","TWN":"那個？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 갑자기 왜 그러나?","JPN":"うん？　急にどうしたんだ？","ENG":"Mm? What's wrong?","TWN":"怎麼了嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그 동물 인형이 갖고 싶은 건가?","JPN":"その動物のぬいぐるみが欲しいのかね？","ENG":"Do you want that animal doll?","TWN":"你想要哪個娃娃嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"주인장!","JPN":"店員さん！","ENG":"Owner!","TWN":"老闆！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"여기 이 인형 좀 계산해 주게! 더 큰 사이즈가 있으면 그것도 같이!","JPN":"このぬいぐるみのお会計を頼みたい。もっと大きいサイズがあればそれも一緒に！","ENG":"I want to buy this doll. If you have it in a bigger size, I want that, too.","TWN":"那個娃娃幫我包起來！還有更大隻的嗎？有的話也幫我包起來！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"네, 잠시만 기다려 주세요.","JPN":"はい、少々お待ちください。","ENG":"Sure, just give me a moment.","TWN":"沒問題～請稍等～"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어떤가, 가은 양. 원한다면 저 인형을 본딴 황금상을 주문 제작 할 수도 있다네.","JPN":"どうかね、ユキさん。望むならあのぬいぐるみそっくりの黄金像をオーダーメイドすることもできるぞ。","ENG":"What do you think, Gaeun? If you want, I can even order a golden statue of that doll for you.","TWN":"怎麼樣？你喜歡的話，我還可以弄個那個娃娃的純金版給你！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내가 이래봬도 그쪽 업계에선 꽤나 알아주는 VIP……","JPN":"こう見えて私はその業界ではかなり有名なVIP……","ENG":"Believe it or not, I'm a VIP customer in that industry—","TWN":"不要看我像個破銅爛鐵，我在精品界可是VIP呢……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"가은 양?","JPN":"ユキさん？","ENG":"Gaeun?","TWN":"嘉恩？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"아, 죄송해요.","JPN":"あ、すみません。","ENG":"Oh, sorry.","TWN":"喔，抱歉。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"이걸 보니 잠깐…… 예전 일이 떠올랐어요.","JPN":"これを見ていたらちょっと……昔のことを思い出しました。","ENG":"Looking at this reminded me of the old days.","TWN":"看到這個……就讓我想起以前的事。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음, 표정을 보니 인형에 대한 기억치고 썩 즐거운 기억은 아닌 모양이군.","JPN":"ほう、その表情を見る限り、ぬいぐるみの思い出にしてはあまり楽しいものではなさそうだな。","ENG":"Hm, by the look on your face, whatever you remembered must not be pleasant.","TWN":"嗯，從你的表情看來似乎不是什麼好事。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그래 보였나요?","JPN":"そう見えますか？","ENG":"Can you tell?","TWN":"我的表情不好嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"……예전에 가지고 있던 동물 인형이 저 정도 크기였어요.","JPN":"……昔持っていた動物のぬいぐるみが、ちょうどあのくらいの大きさでした。","ENG":"... I used to have an animal doll that size.","TWN":"……我以前的娃娃就差不多那麼大。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"두고 온 인형에 미련이 남나?","JPN":"置いてきたぬいぐるみに未練があるのかね？","ENG":"Did you think of a doll that you left behind?","TWN":"是想念被留在那裡的娃娃嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"……그때의 전 인형을 그곳에서 만난 친구에게 줬거든요.","JPN":"……そのぬいぐるみは、そこで出会った友達にあげたんです。","ENG":"... I gave it to a friend that I met in that place.","TWN":"……那時候我把娃娃送了給在那個地方遇到的朋友。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"잊었다고 생각했는데…… 어째서인지 요새는 그 인형이 머릿속을 계속 맴돌아요.","JPN":"忘れたと思っていたのに……なぜかこの頃、そのぬいぐるみのことが頭から離れません。","ENG":"I thought I forgot, but... for some reason, I've been thinking about that doll for some time now.","TWN":"我還以為我已經忘了……但不知道為什麼，最近常常會想到那個娃娃。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"지금의 전 선생님과 함께 이렇게 행복한데, 지금 와서 갑자기 그러다니 이상하죠?","JPN":"今の私は先生と一緒にいてこんなに幸せなのに、なぜか今更思い出したりして、おかしいですよね？","ENG":"I'm so happy with you now, but why am I thinking of that… am I strange?","TWN":"現在的我明明就很幸福，怎麼還會想起以前的事呢？我很怪吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럴 리가. 과거의 물건을 되찾고 싶은 게 이상한 일은 아니라네.","JPN":"そんなことはないさ。過去の物を取り戻したいのはおかしなことではない。","ENG":"Actually, you're not. It's not strange that you want to have back something from your past.","TWN":"怎麼會呢！想找回以前的東西一點都不怪。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"게다가 그건 자네의 지난 시절과 관련된 몇 없는 물건이 아닌가.","JPN":"それに、それは君の過去に関わる数少ない物じゃないか。","ENG":"Especially, if it's one of the few things related to your past.","TWN":"而且那應該是少數與你過去有關的東西吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 가은 양이 먼저 과거의 얘길 꺼내다니 의외로군.","JPN":"しかし、ユキさんが過去の話を持ち出すなんて意外だな。","ENG":"But I'm surprised. You never mention your past unless you're asked.","TWN":"不過，我沒想到你會先提起這個話題。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"요즘 들어서…… 꿈을 꾸기 시작했거든요.","JPN":"最近……夢を見始めたんです。","ENG":"Lately I've been... dreaming about it.","TWN":"　　"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"꿈?","JPN":"夢？","ENG":"Dreaming about it?","TWN":"是什麼夢呢？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"괜찮다면, 어떤 꿈이었는지 말해 보겠나?","JPN":"よかったら、どんな夢だったか教えてくれないか？","ENG":"Mind if I ask what kind of dream?","TWN":"你願意告訴我嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"밤마다 이 인형을 갖고 있는 제 모습이 보여요.","JPN":"毎晩、このぬいぐるみを持っている自分の姿が見えます。","ENG":"Every night, I see myself in my dream, holding this doll.","TWN":"每晚在夢裡我都會看見我抱著那個娃娃。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"무서운 사람들이 총을 들고 지키고 있는…… 돌아갈 곳 없는 아이들로 가득한 창고에서 웅크려있는 제 모습이요.","JPN":"恐い人たちが銃を持って守っている……\\n帰る場所のない子どもたちでいっぱいの倉庫で、うずくまっている自分の姿です。","ENG":"I'm in a warehouse guarded by scary-looking men with guns that's filled with orphans like me.","TWN":"在那個倉庫裡，有一群人拿著槍……看守著無處可去的小孩，而我就縮在角落裡。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그건 꿈이지만, 생생한 감정이 느껴져요.","JPN":"確かに夢だけど、生々しい感情を感じるんです。","ENG":"I know I'm just dreaming, but still, I can feel the emotions again as if it were yesterday.","TWN":"雖然是在夢境裡，感覺卻非常真實。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"슬프면서도…… 안타깝고, 그리운 기분이었어요.","JPN":"悲しくて……切なくて、懐かしい気持ちでした。","ENG":"The sadness, grief... and yearning.","TWN":"傷心的感覺……難過的感覺、想念的感覺。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그 꿈이 마음에 걸리는 거라면, 뭔가 해결할 방법은 없겠나?","JPN":"その夢が気がかりなら、何か解決できる方法はないかね？","ENG":"That dream might have to do with something that's been bothering you. Is it solvable?","TWN":"既然你這麼在意這個夢，那有什麼解決方法嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그건…… 아마도 안 될 거예요.","JPN":"それは……たぶん無理だと思います。","ENG":"I doubt it.","TWN":"嗯……可能沒有。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"이젠 너무 많은 시간이 흘러버렸거든요.","JPN":"あまりにも長い時間が経ってしまったので。","ENG":"Too much time has passed already.","TWN":"畢竟已經是很久以前的事，"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"반군들에게 잡힌 아이들이 어떤 결말을 맞게 되는지, 직접 본 적은 없지만…… 대우가 결코 좋지 않다는 건 알고 있어요.","JPN":"反乱軍に捕まった子どもたちがどんな結末を迎えたのか、\\n直接見たことはないのですが……待遇は決してよくなかったことを覚えています。","ENG":"I've never seen what really happens to the children who got captured by the rebels, but I know they're not treated well.","TWN":"而且雖然我沒親眼見到那些被叛軍抓走的小孩，後來落得什麼樣的下場……但結果想必是不太好的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"そうか。","ENG":"I see.","TWN":"說的也是。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그 시절의 가은 양은 눈이 좋지 않았었지.","JPN":"あの頃のユキさんは目がよくなかったからな。","ENG":"At that time, you couldn't see clearly.","TWN":"那的時候你的眼睛也不太好對吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"네, 선생님 덕분에 회복할 수 있었지만요.","JPN":"はい、先生のおかげで回復しました。","ENG":"No, and I still would have if it weren't for you.","TWN":"是呀，後來是因為你我才能恢復視力的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇다면 가은 양이 말한 그 꿈은, 가은 양 것이 맞는 건가?","JPN":"ではユキさんが言ったその夢は、本当にユキさんの夢なのかな？","ENG":"Then, Gaeun, this dream. Are you sure it's even yours?","TWN":"這樣的話，你說的那夢真的是你的夢嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"네? 그건……","JPN":"はい？　それは……","ENG":"Sorry? That's...","TWN":"嗯？那是……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그러고 보니……","JPN":"そういえば……","ENG":"Now that you mention it...","TWN":"這麼說來……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"전 총을 들고 있는 사람들도, 그곳에 있는 아이들도 실제로 본 적이 없어요.","JPN":"私は銃を持っている人たちも、そこにいる子どもたちも実際に見たことはありません。","ENG":"I never actually saw the people with guns or the children when I was there.","TWN":"拿著槍的人和那些小孩，我都沒親眼見過，"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"하지만 꿈 속에선 분명……","JPN":"でも夢の中では確かに……","ENG":"But in my dreams, everything looks so...","TWN":"但在夢裡卻……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"또렷이 보였겠지. 자네의 어린 시절 모습과 함께 말이야.","JPN":"はっきり見えていたんだろう。君の幼いころの姿とともに。","ENG":"Clear. Including your own self.","TWN":"栩栩如生對吧？就像是你的童年一樣。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그렇다면 그건…… 그곳에 있던 다른 사람의 기억?","JPN":"つまりあれは……そこにいた他のだれかの記憶？","ENG":"Then... am I seeing the memories of someone else who was there with me?","TWN":"意思是……那是別人的回憶？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"이상해요. 어떻게 이런 일이 가능한 거죠?","JPN":"おかしいです。どうしてそんなことができるんでしょう？","ENG":"But that doesn't make sense. How is it even possible?","TWN":"真奇怪，怎麼會有這種事？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"서로가 각자의 꿈을 공유하는 건 도시전설 같지만, 불가능한 기술은 아니라네.","JPN":"人間同士それぞれの夢を共有するのは都市伝説みたいな話だが、不可能な技術ではない。","ENG":"Sharing dreams with others may sound like an urban legend, but it's not completely impossible.","TWN":"彼此分享同一個夢境雖然很不可思議，但也不是不可能。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내 생각이 맞다면, 가은 양이 꾼 꿈의 주인은 아직 살아 있을 걸세.","JPN":"私の考えが正しければ、ユキさんが見た夢の元の持ち主はまだ生きているだろう。","ENG":"If I'm right, the owner of the memories you've seen must still be alive.","TWN":"我沒猜錯的話，那個夢的主人應該還活著。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"아……!","JPN":"えっ……！","ENG":"Ah!","TWN":"哦……！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그게 정말인가요, 선생님?","JPN":"それは本当ですか、先生？","ENG":"Teacher, do you really think so?","TWN":"真的嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇지만.","JPN":"しかし。","ENG":"Yes, but...","TWN":"話雖如此，"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"때로는 알고서도 포기해야 하는 희망이 있다네.","JPN":"時には、わかっていながら諦めなければならない希望もある。","ENG":"Some things are better left alone.","TWN":"但有時候期待越大失望也越大，"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"원한다고 해서 모든 것을 구할 순 없는 법이니까.","JPN":"望んだからといって、すべてを手に入れることはできないものだからね。","ENG":"You can't have everything simply because you want it.","TWN":"畢竟不是所有事都能夠如我們所願。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 지금의 자네라면, 적어도 시도는 해 볼 수 있겠지.","JPN":"でも今の君なら、試してみることぐらいはできるだろう。","ENG":"But it never hurts to try.","TWN":"但現在的你起碼能夠嘗試看看吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어떻게 할 텐가?","JPN":"どうするかね？","ENG":"What do you want to do?","TWN":"你打算怎麼做呢？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"하루는 꿈 속에서……","JPN":"ある時は夢の中で……","ENG":"One time...","TWN":"我在夢裡……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"도로를 걷고 있었어요.","JPN":"道路を歩いていました。","ENG":"I was walking on the road in my dreams.","TWN":"就是不斷地走著，"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"샤레이드로 향하는 50호선 고속도로.","JPN":"シャレードに向かう高速道路50号線。","ENG":"I-50, toward Charade.","TWN":"在前往查雷德的50號線高速公路上。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"선생님과 함께 걷던 그 길을, 이번엔 혼자 걷고 있었어요.","JPN":"先生と一緒に歩いたその道を、あの時は一人で歩いていました。","ENG":"The road I walked with you. In that dream, I was walking alone.","TWN":"和你一起走過的那條路，這次是我獨自走著。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그 꿈이 그 아이가 살아 있다는 증거라면……","JPN":"その夢が、あの子が生きているという証拠なら……","ENG":"If that dream means the owner of the memories is alive, then...","TWN":"若那個夢代表那孩子還活著……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"거기서 다시 만날 수 있을지도 몰라요.","JPN":"そこでまた会えるかもしれません。","ENG":"Maybe I can meet her there.","TWN":"或許能夠在那裡再次見到她。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그 친구를…… 돕고 싶어요.","JPN":"あの子を……助けたいです。","ENG":"I want to... help her.","TWN":"我……想幫助她。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"잘 알겠네.","JPN":"わかった。","ENG":"Understood.","TWN":"我明白了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아쉽지만, 시내에서의 데이트는 다음으로 미뤄둬야겠군.","JPN":"残念だが、市内でのデートはまた今度にするとしよう。","ENG":"I'm sorry, but we'll have to postpone our date in the city.","TWN":"真可惜，我們的約會要等到下次囉～"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};